const body = $input.first().json.body || $input.first().json;

const name = body.name || body.full_name || 'there';
const email = body.email || '';
const message = body.message || body.inquiry || body.notes || '';
const service = body.service || body.service_interest || body.subject || 'your inquiry';
const phone = body.phone || body.telephone || '';
const company = body.company || body.business || '';

if (!email) throw new Error('No email found in form submission');

return [{
  json: {
    name,
    email,
    message,
    service,
    phone,
    company,
    submitted_at: new Date().toISOString(),
    raw: body
  }
}];

