parameters.jsCode:
const raw = $input.first().json.choices[0].message.content;

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  // strip any accidental markdown fences
  const cleaned = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
}

const lead = $('Parse Form Fields').first().json;

return [{
  json: {
    ...lead,
    score: parsed.score,
    tier: parsed.tier,
    intent_summary: parsed.intent_summary,
    urgency: parsed.urgency,
    email_subject: parsed.reply_email.subject,
    email_body: parsed.reply_email.body,
    slack_note: parsed.slack_note,
    is_hot: parsed.score >= 8
  }
}];

